Here is a comprehensive set of **pytest**-style unit tests for the `flatten_dict` function, covering:

- **Happy path** scenarios (e.g., nested dictionaries, flat dictionaries)
- **Edge cases** (e.g., empty dictionaries, keys with empty strings)
- **Error cases** (e.g., invalid input types, non-string separators)

---

### ✅ Unit Tests for `flatten_dict`

```python
import pytest

def flatten_dict(d: dict, parent_key: str = '', sep: str = '.') -> dict:
    items = []
    for k, v in d.items():
        new_key = f'{parent_key}{sep}{k}' if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep).items())
        else:
            items.append((new_key, v))
    return dict(items)


# ---------------------------
# Happy Path Test Cases
# ---------------------------

def test_flatten_dict_happy_path():
    input_dict = {'a': 1, 'b': {'c': 2, 'd': {'e': 3}}}
    expected = {'a': 1, 'b.c': 2, 'b.d.e': 3}
    result = flatten_dict(input_dict)
    assert result == expected


def test_flatten_dict_flat():
    input_dict = {'a': 1, 'b': 2}
    expected = {'a': 1, 'b': 2}
    result = flatten_dict(input_dict)
    assert result == expected


def test_flatten_dict_empty_dict():
    input_dict = {}
    expected = {}
    result = flatten_dict(input_dict)
    assert result == expected


def test_flatten_dict_with_empty_key():
    input_dict = {'': 1}
    expected = {'': 1}
    result = flatten_dict(input_dict)
    assert result == expected


# ---------------------------
# Edge Case Test Cases
# ---------------------------

def test_flatten_dict_with_parent_key():
    input_dict = {'a': 1}
    expected = {'x.a': 1}
    result = flatten_dict(input_dict, parent_key='x')
    assert result == expected


def test_flatten_dict_with_custom_separator():
    input_dict = {'a': {'b': 1}}
    expected = {'a-b': 1}
    result = flatten_dict(input_dict, sep='-')
    assert result == expected


def test_flatten_dict_with_nested_parent_key():
    input_dict = {'a': {'b': {'c': 1}}}
    expected = {'x.a.b.c': 1}
    result = flatten_dict(input_dict, parent_key='x')
    assert result == expected


# ---------------------------
# Error Case Test Cases
# ---------------------------

def test_flatten_dict_non_dict_input():
    with pytest.raises(TypeError):
        flatten_dict([1, 2, 3])


def test_flatten_dict_non_string_separator():
    input_dict = {'a': {'b': 1}}
    with pytest.raises(TypeError):
        flatten_dict(input_dict, parent_key='x', sep=1)


def test_flatten_dict_non_string_parent_key():
    input_dict = {'a': {'b': 1}}
    with pytest.raises(TypeError):
        flatten_dict(input_dict, parent_key=1)


def test_flatten_dict_invalid_key_type():
    input_dict = {1: {'b': 1}}
    with pytest.raises(TypeError):
        flatten_dict(input_dict)
```

